        ["DIFC/DFSA", "Dubai International Financial Centre / Dubai Financial Services Authority", "Part of 100+"],
        ["CBUAE", "Central Bank of the UAE (Federal)", "Part of 100+"],
        ["CMA", "Securities and Commodities Authority (Federal)", "Part of 100+"]
